@startuml
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor #000000
  ArrowColor #000000
}

skinparam stereotypeCBackgroundColor #C8E6C9
skinparam stereotypeEBackgroundColor #FFCCBC

class "PubSubEvent`1" as PubSubEvent {
}
note right of PubSubEvent
  T
end note

class "UserPreLoginEvent" as UserPreLoginEvent {
}

class "LoginArgs" as LoginArgs {
  + LoginArgs(user:IUser, phase:LoginPhase)
}

class "LoginPhase" as LoginPhase {
  Request,
  Response,
  Success,
}

class "IUser" as IUser {
}

UserPreLoginEvent --|> PubSubEvent : <LoginArgs>
LoginArgs --> LoginPhase : Phase
LoginArgs --> IUser : User

@enduml
